var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"흐음…","JPN":"ふーん……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"정말 실망이야 언니.","JPN":"もうガッカリだよ、マブカさん。","ENG":"I'm disappointed in you, Mavka.","TWN":"真是讓人失望，姊姊。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"조금은 기대했는데, 침식체 따위가 뭐가 그리 불쌍하다고…","JPN":"少しは期待してたけど、侵食体の何がそんなに可哀想なの……","ENG":"I was looking forward to this, but how can you pity these C.O.s...?","TWN":"雖然有點期待，但侵蝕體有什麼好可憐的……"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"아쉽네. 잘하면 사샤언니를 낫게 해줬을텐데…","JPN":"残念だね。結果次第でサシャさんを治してあげたのに……","ENG":"What a shame. You could've helped Sasha get better...","TWN":"真可惜，要是能治好莎夏姊姊就好了……"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛, 다 뻥이지만.","JPN":"ひひっ、全部ウソだけど。","ENG":"Hehe, even though I'm lying.","TWN":"嘻嘻，其實都是騙人的。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>…….</color>","JPN":"<color=#ffd34c>……</color>","ENG":"<color=#ffd34c>...</color>","TWN":"<color=#ffd34c>……</color>"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"언니도 곧 우리들의 <color=#ffd34c>가족</color>이 될 거야.","JPN":"サシャさんももうすぐ私たちの<color=#ffd34c>家族</color>になるよ。","ENG":"You'll soon become our <color=#ffd34c>family</color> too.","TWN":"姊姊也會很快成為我們<color=#ffd34c>家裡</color>的一員。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그거 알아? 사실 사샤 언니를 치료할 방법은 어디에도 없어.","JPN":"知ってる？　実はサシャさんを治療する方法なんてどこにもないの。","ENG":"Did you know? There's no way to treat Sasha, actually.","TWN":"你知道嗎？其實沒有任何方法能治好莎夏姊姊。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그림자병을 치료하다니… 말도 안 되잖아?","JPN":"シャドウ病を治療するなて……あり得ないでしょう？","ENG":"Treating a Shadow disease...? That makes no sense.","TWN":"治癒暗影……這根本不可能吧？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"사샤언니가 그림자로 붕괴하면 사람들을 마구 죽였을지도 몰라.","JPN":"サシャさんがシャドウに崩壊すると、人を大勢殺したかもしれない。","ENG":"But if Sasha does become a Shadow, she might kill countless people.","TWN":"如果莎夏姊姊變成了暗影，可能會害死很多人。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그래서 내가 직접 곁에서 보살펴주고 싶었는데….","JPN":"だから私が直接そばで見てあげたかったんだけど……","ENG":"That's why I wanted to be there for her and take care of her...","TWN":"所以我想親自照顧她……"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"박사님은 좀 더 좋은 생각이 떠오르신 것 같아.","JPN":"博士はもっといいことを思いついたみたい。","ENG":"But the doctor seems to have come up with a better idea.","TWN":"但博士好像有更好的主意。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>......안돼.</color>","JPN":"<color=#ffd34c>……ダメ。</color>","ENG":"<color=#ffd34c>...No.</color>","TWN":"<color=#ffd34c>不要……</color>"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛. 곧 알게 될 거니까 무리해서 움직이지 않아도 돼.","JPN":"ひひっ。じきに知ることになるから、無理に動かなくてもいいよ。","ENG":"Hehe, you'll find out soon enough. So don't push yourself.","TWN":"嘻嘻，你很快就會知道了，不用勉強自己。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"있지…? 사샤언니가 나 때렸을 때… 솔직히 조금 아팠다?","JPN":"そうそう……。サシャさんに殴られた時……正直ちょっと痛かったの。","ENG":"Hey... When Sasha slapped me... it kind of hurt. Did you know that?","TWN":"其實啊……莎夏姊姊打我的時候……還是有點痛的？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"사과해 줬으면 좋았을 텐데… 이젠 그럴 수도 없겠네.","JPN":"謝ってくれればよかったのに……もうそれもできそうにないね。","ENG":"I wish she'd apologize to me, but... I guess that's out of the picture now.","TWN":"如果她能道歉就好了……雖說現在已經不可能了。"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"음… 슬슬 언니가 올 때가 됐는데, 얼마나 걸리려나?","JPN":"うーん……そろそろ姉さんが来る頃なのに、いつまでかかるのかな？","ENG":"Mm... Eva should be back by now. What's taking her so long?","TWN":"嗯……姊姊差不多該來了，就是不知道還要多久？"},"stage":{"bg":"FLOOR_FACILITY_01","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"제, 제가요…?! 전….","JPN":"わ、私がですか……！？　私は……","ENG":"M-me...?! But I...","TWN":"我，我嗎……？！我……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"전 못해요…!","JPN":"私はできませんよ……！","ENG":"I can't do it...!","TWN":"我做不到……！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"네 마음 잘 안다 에바.","JPN":"お前の気持ちはわかる、エヴァ。","ENG":"I know how you feel, Eva.","TWN":"我很了解你的心情，耶娃。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"하지만 사샤는 이미 그림자가 되었어.","JPN":"だが、サシャはすでにシャドウになったんだ。","ENG":"But Sasha has already become a Shadow.","TWN":"但是莎夏已經變成了暗影。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"그림자임에도 공격성을 띠고 있지 않는건 정말 의외지만… 곧 시간문제야.","JPN":"シャドウではあるが攻撃性を見せていないのは本当に意外だが……それも時間の問題だ。","ENG":"It's unusual that a Shadow isn't being aggressive... but it's only a matter of time.","TWN":"雖然她作為暗影卻沒有表現出攻擊性，這是個意外……但這只是時間問題。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"이대로라면 가만히 있는 것 만으로도 주변에 큰 피해를 주게 될 거다.","JPN":"このままでは、こうしているだけでも周りに大きな被害をもたらすだろう。","ENG":"Just leaving her like this will cause tremendous damage to those around us.","TWN":"照這樣下去，光是讓她待在這裡就會對周圍造成巨大傷害。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EVA_DOLL_NPC_NULL","text":{"KOREA":"하, 하지만 분명 치료해 준다고…!","JPN":"で、でも治療してくれるって……！","ENG":"B-but you said you'd treat her...!","TWN":"可，可是你說會治好她的……！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"에바. 마음 단단히 먹어야 한다.","JPN":"エヴァ。覚悟を決めるんだ。","ENG":"Eva. You need to be strong.","TWN":"耶娃，你必須要堅定決心。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"걱정할 것 없어. 넌 그저 명령에 따랐을 뿐이야.","JPN":"心配することはない。お前はただ命令に従っただけだ。","ENG":"There's nothing to worry about. You're just following orders.","TWN":"不用擔心，你只是遵從命令而已。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"지금까지 많이 힘들었지?","JPN":"今まで大変だっただろう？","ENG":"It's been pretty difficult, hasn't it?","TWN":"到現在為止你很辛苦吧？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DOCTOR_DOLL_NPC_NULL","text":{"KOREA":"다 괜찮다. 곧 너와 드레카바크, 다 행복해질 테니까.","JPN":"もう大丈夫だ。お前とドレカバク、すぐにみんな幸せになるはずだから。","ENG":"It's all right. Soon, you and Drekavac will become happy.","TWN":"一切都會好起來的，很快你和德蕾卡娃克都會幸福的。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};